// Colors below were migrated from saved paint into code via api.paint.*
// (the model is now self-colouring; see /ai/colors.md). Edit colours here.
const __pwModel = (() => {
const { Manifold, label } = api;

function box(min, max) {
  const s = [max[0] - min[0], max[1] - min[1], max[2] - min[2]];
  const c = [(min[0] + max[0]) / 2, (min[1] + max[1]) / 2, (min[2] + max[2]) / 2];
  return Manifold.cube(s, true).translate(c);
}

// Front face normal is -Y. A Z-axis cylinder rotated [90,0,0] points its axis
// along -Y, so its circular face lies in the XZ plane and reads as a CIRCLE
// from the front.
function roundBtn(cx, cz, r, backY, depth) {
  return Manifold.cylinder(depth, r, r) // along +Z, z in [0, depth]
    .rotate([90, 0, 0]) // axis -> -Y; spans y in [-depth, 0]
    .translate([cx, backY, cz]); // back face at y=backY, front proud at backY-depth
}

// A rounded "pill" (stadium): hull of two coaxial Y-axis discs.
function pillBtn(cx, cz, halfLen, r, backY, depth) {
  const a = roundBtn(-halfLen, 0, r, backY, depth);
  const b = roundBtn(+halfLen, 0, r, backY, depth);
  return a.add(b).hull().translate([cx, 0, cz]);
}

// Body: 16w x 26h x 5d, front face at y=-2.5.
// Round the BARE shell first — api.round remeshes and destroys labels/paint,
// so every feature (bezel/screen/dpad/buttons/speaker) is added AFTER this,
// and labeling/painting happens after that. Radius 1.2 reads as molded
// plastic corners without eating the 5-unit body depth (thinnest dimension) —
// a larger radius (tried 1.8) over-rounds this thin a shell into a pill/capsule
// and buries the flat front-face features (screen/dpad) under the bulge.
const bodyBox = box([-8, -2.5, -13], [8, 2.5, 13]);
const body = api.round(bodyBox, { radius: 1.2 });

const Yf = -3.0;
const Yb = -1.0;

const btnBackY = -1.0;
const btnDepth = 2.4;

// Screen bezel + green screen
const bezel = box([-5.5, Yf, 2.0], [5.5, Yb, 11.5]);
const screen = box([-4.5, Yf - 0.1, 2.8], [4.5, Yb, 10.8]);

// D-pad: PLUS cross (kept)
const dpadH = box([-7.5, Yf, -5.5], [-3.5, Yb, -3.8]);
const dpadV = box([-6.25, Yf, -6.8], [-4.75, Yb, -2.5]);

// A / B action buttons: ROUND raised discs, placed DIAGONALLY.
const btnR = 1.4;
const btnB = roundBtn(3.6, -5.9, btnR, btnBackY, btnDepth); // lower-left
const btnA = roundBtn(6.1, -4.2, btnR, btnBackY, btnDepth); // upper-right

// Start / Select: two small rounded pills, angled slightly, near center-bottom.
const ssDepth = 1.9;
const ssBackY = -1.0;
const startBtn = pillBtn(-1.5, -8.4, 0.55, 0.5, ssBackY, ssDepth);
const selectBtn = pillBtn(1.5, -8.4, 0.55, 0.5, ssBackY, ssDepth);
const startSel = startBtn.add(selectBtn).rotate([0, -22, 0]);

// Speaker grille: diagonal slots, lower-right.
function slot(cx, cz, len) {
  return box([-len / 2, Yf, -0.27], [len / 2, Yb, 0.27])
    .rotate([0, -32, 0])
    .translate([cx, 0, cz]);
}
const sp1 = slot(5.2, -8.7, 4.0);
const sp2 = slot(5.2, -9.5, 4.0);
const sp3 = slot(5.2, -10.3, 4.0);
const sp4 = slot(5.2, -11.1, 4.0);

const allFeatures = bezel.add(screen).add(dpadH).add(dpadV)
  .add(btnA).add(btnB)
  .add(startSel)
  .add(sp1).add(sp2).add(sp3).add(sp4);

const fullBody = label(body.add(allFeatures), 'body');

const bezelL = label(bezel, 'bezel');
const screenL = label(screen, 'screen');
const dpadL = label(dpadH.add(dpadV), 'dpad');
const btnAL = label(btnA, 'btnA');
const btnBL = label(btnB, 'btnB');
const ssL = label(startSel, 'startselect');
const spL = label(sp1.add(sp2).add(sp3).add(sp4), 'speaker');

return fullBody.add(bezelL).add(screenL).add(dpadL)
  .add(btnAL).add(btnBL).add(ssL).add(spL);
})();
api.paint.label("body", [0.78, 0.78, 0.74]);
api.paint.label("screen", [0.55, 0.7, 0.4]);
api.paint.label("dpad", [0.2, 0.2, 0.22]);
api.paint.label("btnA", [0.62, 0.12, 0.28]);
api.paint.label("btnB", [0.62, 0.12, 0.28]);
api.paint.label("startselect", [0.25, 0.25, 0.28]);
api.paint.label("speaker", [0.25, 0.25, 0.28]);
return __pwModel;
